const staticData = $getWorkflowStaticData("global");
const sentUrls = Array.isArray(staticData.sentNewsUrls) ? staticData.sentNewsUrls : [];
staticData.sentNewsUrls = sentUrls.slice(-300);
const sentSet = new Set(staticData.sentNewsUrls);
const cutoffMs = Date.now() - 36 * 60 * 60 * 1000;
function firstValue(values) {
  for (const value of values) {
    if (value !== undefined) {
      if (value !== null) {
        if (value !== "") return value;
      }
    }
  }
  return "";
}
function stripHtml(value) {
  return String(value ?? "")
    .replace(/<[^>]*>/g, "")
    .replace(/&quot;/g, "\"")
    .replace(/&#x27;/g, "'")
    .replace(/&amp;/g, "&")
    .replace(/\s+/g, " ")
    .trim();
}
function normalizeUrl(value) {
  try {
    const url = new URL(String(value ?? ""));
    url.hash = "";
    for (const key of ["utm_source", "utm_medium", "utm_campaign", "utm_term", "utm_content"]) url.searchParams.delete(key);
    return url.toString();
  } catch (_err) {
    return String(value ?? "").trim();
  }
}
function sourceFromUrl(url) {
  const value = String(url ?? "").toLowerCase();
  if (value.includes("reddit.com")) return "Reddit";
  if (value.includes("github")) return "GitHub";
  if (value.includes("hnrss")) return "Hacker News";
  if (value.includes("news.ycombinator")) return "Hacker News";
  if (value.includes("openai")) return "OpenAI";
  if (value.includes("huggingface")) return "Hugging Face";
  if (value.includes("n8n")) return "n8n";
  return "News";
}
const rawItems = $input.all().map((item) => item.json ?? {});
const normalized = [];
for (const item of rawItems) {
  const title = stripHtml(firstValue([item.title, item.name, item.story_title]));
  const url = normalizeUrl(firstValue([item.link, item.url, item.guid, item.id]));
  const summary = stripHtml(firstValue([item.contentSnippet, item.content, item.description, item.summary, item.text]));
  if (!title) continue;
  if (!url) continue;
  const rawDate = firstValue([item.isoDate, item.pubDate, item.created, item.updated, item.date]);
  const time = rawDate ? Date.parse(rawDate) : 0;
  if (time) {
    if (time < cutoffMs) continue;
  }
  normalized.push({
    title,
    url,
    source: sourceFromUrl(url),
    summary,
    feedScore: Number(firstValue([item.points, item.score, 0])),
    publishedAt: rawDate,
  });
}
const deduped = [];
const keys = new Set();
for (const item of normalized) {
  const titleKey = item.title.toLowerCase().replace(/[^a-z0-9\u3400-\u9fff]+/gi, " ").trim().slice(0, 120);
  const key = item.url ? item.url : titleKey;
  if (!key) continue;
  if (keys.has(key)) continue;
  if (sentSet.has(item.url)) continue;
  keys.add(key);
  deduped.push(item);
}
deduped.sort((a, b) => Number(b.feedScore ?? 0) - Number(a.feedScore ?? 0));
const candidates = deduped.slice(0, 60).map((item, index) => ({ index, ...item }));
const scorePrompt = [
  "You score daily AI/dev-tools news candidates for a Hong Kong WhatsApp digest.",
  "Return JSON only. No markdown.",
  "Score each candidate 0-10 by importance for AI/LLM/developer-tools readers.",
  "Prefer: AI model/tool releases, coding agents, open-source AI tools, developer workflow changes, n8n/automation, practical engineering impact.",
  "Penalize: generic chatter, duplicates, weak Reddit posts, old or unclear items, crypto/finance unless strongly related to AI/dev tools.",
  "Output shape: {\"items\":[{\"index\":0,\"score\":8,\"reason\":\"short reason\"}]}",
  "Candidates JSON:",
  JSON.stringify(candidates, null, 2),
].join("\n");
return [{ json: { candidates, candidateCount: candidates.length, messages: [{ role: "user", content: scorePrompt }] } }];

const source = $("Build News Candidates").first().json;
const candidates = Array.isArray(source.candidates) ? source.candidates : [];
const rawOutput = $input.first().json;
const raw = String(rawOutput.text ?? rawOutput.output ?? rawOutput.response ?? rawOutput.message?.content ?? rawOutput.choices?.[0]?.message?.content ?? "");
function parseJson(text) {
  const fence = String.fromCharCode(96, 96, 96);
  const cleaned = String(text ?? "")
    .replace(new RegExp("^" + fence + "json\\s*", "i"), "")
    .replace(new RegExp("^" + fence + "\\s*", "i"), "")
    .replace(new RegExp(fence + "$", "i"), "")
    .trim();
  return JSON.parse(cleaned);
}
let parsed;
try {
  parsed = parseJson(raw);
} catch (_err) {
  parsed = { items: candidates.map((item) => ({ index: item.index, score: 5, reason: "score-parse-fallback" })) };
}
const byIndex = new Map(candidates.map((item) => [Number(item.index), item]));
const scored = (Array.isArray(parsed.items) ? parsed.items : [])
  .map((scoreItem) => {
    const candidate = byIndex.get(Number(scoreItem.index));
    if (!candidate) return null;
    return {
      ...candidate,
      aiScore: Math.max(0, Math.min(10, Number(scoreItem.score) ? Number(scoreItem.score) : 0)),
      aiReason: String(scoreItem.reason ?? ""),
    };
  })
  .filter(Boolean)
  .sort((a, b) => {
    const aiDiff = b.aiScore - a.aiScore;
    if (aiDiff !== 0) return aiDiff;
    return Number(b.feedScore ?? 0) - Number(a.feedScore ?? 0);
  });
const top10 = scored.slice(0, 10);
const top5 = top10.slice(0, 5);
const briefingPrompt = [
  "You are a sharp AI/dev-tools news editor writing for a Hong Kong WhatsApp group.",
  "Write a beautiful, compact Traditional Chinese message from the top scored items.",
  "Use exactly 5 items if available. Keep each item short and useful.",
  "Tone: smart, concise, friendly Hong Kong style. No long essay.",
  "Format exactly like this:",
  "?? ????? AI / Dev ??",
  "",
  "1?? <short title>",
  "???<one sentence>",
  "??????<one sentence>",
  "?? <source or URL>",
  "",
  "Finally add:",
  "?? ????????<one practical takeaway>",
  "",
  "Top scored items JSON:",
  JSON.stringify(top10, null, 2),
].join("\n");
return [{ json: { ...source, scoredItems: scored, top10, top5, scoreRaw: raw, messages: [{ role: "user", content: briefingPrompt }] } }];

const targetGroupId = "120363410636974224@g.us";
const llm = $("Write Daily Briefing").first().json;
const message = String(llm.text ?? llm.output ?? llm.response ?? llm.message?.content ?? llm.choices?.[0]?.message?.content ?? "").trim();
if (!message) throw new Error("Daily briefing message is empty");
const source = $("Keep Top 10").first().json;
const urls = (source.top10 ?? []).map((item) => item.url).filter(Boolean);
const staticData = $getWorkflowStaticData("global");
const existing = Array.isArray(staticData.sentNewsUrls) ? staticData.sentNewsUrls : [];
staticData.sentNewsUrls = Array.from(new Set([...existing, ...urls])).slice(-300);
return [{ json: { to: targetGroupId, message } }];

const source = $("Keep Top 10").first().json;
const brave = $input.first().json;
function textFrom(value) {
  if (value === undefined) return "";
  if (value === null) return "";
  if (typeof value === "string") return value.trim();
  if (Array.isArray(value)) return value.map(textFrom).filter(Boolean).join("\n\n");
  if (typeof value === "object") {
    return [value.title, value.description, value.snippet, value.text, value.content, value.url ? "Source: " + value.url : ""]
      .map(textFrom)
      .filter(Boolean)
      .join("\n");
  }
  return String(value).trim();
}
function firstText(values) {
  for (const value of values) {
    const text = textFrom(value);
    if (text) return text;
  }
  return "";
}
const context = firstText([brave.context, brave.llm_context, brave.full_content, brave.content, brave.results]);
const messages = Array.isArray(source.messages) ? source.messages.map((message) => ({ ...message })) : [];
if (context) {
  const extra = [
    "",
    "External web context from Brave Search for the top scored items:",
    context,
    "Use this only to clarify background, freshness, product names, dates, and source context. Do not add claims not supported by feed items or this context."
  ].join("\n");
  if (messages.length > 0) {
    const last = messages.length - 1;
    messages[last] = {
      ...messages[last],
      content: String(messages[last].content ?? "") + "\n\n" + extra,
    };
  }
}
return [{ json: { ...source, braveContext: context, braveRaw: brave, messages } }];
